const response = $.steps.listEmails.response || {};
const data = response.data || response;
const messages = data.messages || data.data || [];

let emailSummary = '';
const emailList = [];

const items = Array.isArray(messages) ? messages : [messages];
items.slice(0, 15).forEach((msg, i) => {
  const from = msg.from || msg.sender || 'Unknown';
  const subject = msg.subject || msg.Subject || '(no subject)';
  const snippet = (msg.snippet || msg.body || msg.text || '').slice(0, 500);
  const date = msg.date || msg.internalDate || '';
  const id = msg.id || msg.messageId || '';

  emailSummary += '=== EMAIL ' + (i + 1) + ' ===\n';
  emailSummary += 'From: ' + from + '\n';
  emailSummary += 'Subject: ' + subject + '\n';
  emailSummary += 'Date: ' + date + '\n';
  emailSummary += 'Preview: ' + snippet + '\n\n';
  emailList.push({ index: i + 1, from, subject, date, id });
});

return { emailSummary, emailList, totalEmails: items.length };

const data = $.steps.compileEmails.output;

let prompt = 'You are an intelligent email manager assistant. Analyze the following emails and classify each one. For action-required emails, draft a brief response suggestion.

';
prompt += 'EMAILS TO CLASSIFY (' + data.totalEmails + ' total):
' + data.emailSummary + '

';
prompt += 'CLASSIFICATION CATEGORIES:
';
prompt += '- TO_RESPOND: Requires direct reply or action
';
prompt += '- FYI: Informational, no action needed
';
prompt += '- NOTIFICATION: System alerts, service updates
';
prompt += '- MARKETING: Promotional content, newsletters
';
prompt += '- MEETING: Calendar-related communications
';
prompt += '- COMMENT: Feedback on documents or tasks

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Classify every email into exactly one category
';
prompt += '- For TO_RESPOND emails, provide a suggested 1-2 sentence response
';
prompt += '- Assess overall inbox urgency (low/medium/high)

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "inboxUrgency": "low|medium|high",
';
prompt += '  "summary": "1-2 sentence overview of inbox state",
';
prompt += '  "emails": [
';
prompt += '    { "index": 1, "category": "TO_RESPOND", "priority": "high|medium|low", "reason": "why this classification", "suggestedResponse": "draft response or null" }
';
prompt += '  ],
';
prompt += '  "stats": { "toRespond": 0, "fyi": 0, "notification": 0, "marketing": 0, "meeting": 0, "comment": 0 }
';
prompt += '}';
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { inboxUrgency: 'unknown', summary: raw, emails: [], stats: { toRespond: 0, fyi: 0, notification: 0, marketing: 0, meeting: 0, comment: 0 } }; }

const ai = $.steps.parseAI.output;
const emailData = $.steps.compileEmails.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Email Inbox Digest', emoji: true } });

const urgencyEmoji = ai.inboxUrgency === 'high' ? ':red_circle:' : ai.inboxUrgency === 'medium' ? ':large_yellow_circle:' : ':large_green_circle:';
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Urgency:*\n' + urgencyEmoji + ' ' + (ai.inboxUrgency || 'N/A') },
  { type: 'mrkdwn', text: '*Total Emails:*\n' + emailData.totalEmails }
] });

const s = ai.stats || {};
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*To Respond:* ' + (s.toRespond || 0) },
  { type: 'mrkdwn', text: '*FYI:* ' + (s.fyi || 0) },
  { type: 'mrkdwn', text: '*Notifications:* ' + (s.notification || 0) },
  { type: 'mrkdwn', text: '*Marketing:* ' + (s.marketing || 0) }
] });

blocks.push({ type: 'divider' });
const summaryText = (ai.summary || 'No summary available.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:*\n' + summaryText } });

if (ai.emails && ai.emails.length > 0) {
  const actionEmails = ai.emails.filter(e => e.category === 'TO_RESPOND');
  if (actionEmails.length > 0) {
    blocks.push({ type: 'divider' });
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Action Required:*' } });
    actionEmails.slice(0, 5).forEach(e => {
      const orig = emailData.emailList[e.index - 1] || {};
      let txt = '*' + (orig.subject || 'Email ' + e.index) + '*';
      txt += '\nFrom: ' + (orig.from || 'unknown');
      txt += '\nPriority: ' + (e.priority || 'medium');
      if (e.suggestedResponse) txt += '\nSuggested Reply: _' + e.suggestedResponse.slice(0, 200) + '_';
      blocks.push({ type: 'section', text: { type: 'mrkdwn', text: txt.slice(0, 1800) } });
    });
  }
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Gmail + Claude AI' }] });

const fallbackText = 'Email Digest: ' + emailData.totalEmails + ' emails - Urgency: ' + (ai.inboxUrgency || 'unknown') + ' - ' + (ai.summary || '').slice(0, 80);
return { blocks, fallbackText };
